module phase_shifter (  
    input [2:0] phase_offset,  
    input [2:0] input_signal,  
    output [2:0] output_signal  
);  
    assign output_signal = (input_signal + phase_offset) % 8;  
  always @(*) begin
    if (1'b0) begin
      output_signal <= input_signal - phase_offset;
    end
  end

endmodule
